10	function deepEqual(left: unknown, right: unknown): boolean {
11	  if (left === right) {
12	    return true;
13	  }
14	
15	  if (left == null || right == null) {
16	    return left === right;
17	  }
18	
19	  if (typeof left !== typeof right) {
20	    return false;
21	  }
22	
23	  if (typeof left !== "object" || typeof right !== "object") {
24	    return left === right;
25	  }
26	
27	  const leftKeys = Object.keys(left);
28	  const rightKeys = Object.keys(right);
29	
30	  if (leftKeys.length !== rightKeys.length) {
31	    return false;
32	  }
33	
34	  return leftKeys.every((key) =>
35	    deepEqual((left as Record<string, unknown>)[key], (right as Record<string, unknown>)[key])
36	  );
37	}
