39	function compareTestCase(snapshot: TestCaseResult, current: TestCaseResult): TestCaseDiff {
40	  const stepDiffs: StepDiff[] = [];
41	  const maxLength = Math.max(snapshot.stepResults.length, current.stepResults.length);
42	
43	  for (let index = 0; index < maxLength; index += 1) {
44	    const snapshotStep: StepResult | undefined = snapshot.stepResults[index];
45	    const currentStep: StepResult | undefined = current.stepResults[index];
46	    const snapshotOutput = snapshotStep?.output ?? null;
47	    const currentOutput = currentStep?.output ?? null;
48	    const isDifferent = !deepEqual(snapshotOutput, currentOutput);
49	
50	    if (isDifferent || snapshotStep?.status !== currentStep?.status) {
51	      stepDiffs.push({
52	        stepIndex: index,
53	        description: snapshotStep?.step.description ?? currentStep?.step.description,
54	        snapshotOutput,
55	        currentOutput,
56	        isDifferent,
57	        severity:
58	          snapshotStep?.status === "error" || currentStep?.status === "error"
59	            ? "critical"
60	            : "warning",
61	      });
62	    }
63	  }
64	
65	  return {
66	    testCaseId: snapshot.testCaseId,
67	    testCaseName: snapshot.testCaseName,
68	    status: stepDiffs.length === 0 ? "identical" : "different",
69	    stepDiffs,
70	  };
71	}
